export const getAdminGetOrdersUrl = (params?: AdminGetOrdersParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/admin/orders?${stringifiedParams}` : `/api/admin/orders`
}

/**
 * @summary Get all orders (admin)
 */
export const adminGetOrders = async (params?: AdminGetOrdersParams, options?: RequestInit): Promise<Order[]> => {

  return customFetch<Order[]>(getAdminGetOrdersUrl(params),
  {
    ...options,
    method: 'GET'


  }
);}





